import{_ as a,o as r,c as t,ag as o}from"./chunks/framework.BYehg5q7.js";const m=JSON.parse('{"title":"Marker Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"guide/glossary.md","filePath":"guide/glossary.md","lastUpdated":1772287587000}'),s={name:"guide/glossary.md"};function n(i,e,l,h,c,d){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="marker-glossary" tabindex="-1">Marker Glossary <a class="header-anchor" href="#marker-glossary" aria-label="Permalink to &quot;Marker Glossary&quot;">​</a></h1><p>The Marker Glossary is a searchable reference for every biomarker tracked in getbased. Open it any time you want to understand what a marker measures, what the reference and optimal ranges are, or what your latest result was.</p><h2 id="opening-the-glossary" tabindex="-1">Opening the Glossary <a class="header-anchor" href="#opening-the-glossary" aria-label="Permalink to &quot;Opening the Glossary&quot;">​</a></h2><p>Click the <strong>book icon</strong> in the top header. The glossary modal opens over whatever page you are on.</p><h2 id="browsing-by-category" tabindex="-1">Browsing by Category <a class="header-anchor" href="#browsing-by-category" aria-label="Permalink to &quot;Browsing by Category&quot;">​</a></h2><p>Markers are grouped by category — Biochemistry, Hormones, Lipids, Hematology, and so on. Each category has a collapsible header. Click the header to expand or collapse the list of markers within it. All categories start expanded by default.</p><h2 id="searching" tabindex="-1">Searching <a class="header-anchor" href="#searching" aria-label="Permalink to &quot;Searching&quot;">​</a></h2><p>Type in the search box at the top of the glossary to filter markers by name. The list narrows in real time as you type. The search works across all categories simultaneously, so you do not need to know which category a marker belongs to.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Searching for partial words works — typing &quot;creat&quot; will match Creatinine, Creatinine Kinase, and any other marker whose name contains those letters.</p></div><h2 id="what-each-entry-shows" tabindex="-1">What Each Entry Shows <a class="header-anchor" href="#what-each-entry-shows" aria-label="Permalink to &quot;What Each Entry Shows&quot;">​</a></h2><p>For each marker you will see:</p><ul><li><strong>Name</strong> — The full display name of the marker</li><li><strong>Latest value</strong> — Your most recent result for this marker, if you have one</li><li><strong>Reference range</strong> — The standard normal range</li><li><strong>Optimal range</strong> — A tighter range associated with better long-term outcomes, when one is defined</li><li><strong>Description</strong> — A plain-language explanation of what the marker measures and why it matters</li></ul><h2 id="clicking-through-to-detail" tabindex="-1">Clicking Through to Detail <a class="header-anchor" href="#clicking-through-to-detail" aria-label="Permalink to &quot;Clicking Through to Detail&quot;">​</a></h2><p>Click any marker entry in the glossary to close the glossary and open the <strong>detail modal</strong> for that marker. The detail modal shows your full history for that marker, the trend, notes, and an AI interpretation.</p><h2 id="custom-markers" tabindex="-1">Custom Markers <a class="header-anchor" href="#custom-markers" aria-label="Permalink to &quot;Custom Markers&quot;">​</a></h2><p>Markers that were imported from your lab PDFs but are not part of the standard schema appear in the glossary under their assigned category, marked with a bookmark icon. Their descriptions are fetched from the AI the first time you view them.</p>',16)])])}const p=a(s,[["render",n]]);export{m as __pageData,p as default};
